import { Inject, Injectable, Logger } from '@nestjs/common'
import fs from 'fs'
import { compile } from 'handlebars'
import type { Transporter } from 'nodemailer'
import { join } from 'path'

import { requiredEnv } from '../../config/env'

@Injectable()
export class EmailService {
    private readonly logger = new Logger(EmailService.name)
    private readonly from = requiredEnv('SMTP_FROM')
    private readonly templates = new Map<string, HandlebarsTemplateDelegate>()

    constructor(@Inject('EMAIL_CLIENT') private readonly emailClient: Transporter) {}

    async alert(params: { to: string; subject: string; template: string; params: Record<string, unknown> }) {
        if (!/^[a-z0-9_-]+$/i.test(params.template)) throw new Error('Invalid email template name')

        let template = this.templates.get(params.template)
        if (!template) {
            const source = await fs.promises.readFile(join(__dirname, '../../templates/email', `${params.template}.hbs`), 'utf-8')
            template = compile(source)
            this.templates.set(params.template, template)
        }

        const result = await this.emailClient.sendMail({
            from: this.from,
            to: params.to,
            subject: params.subject,
            html: template(params.params),
        })
        this.logger.debug(`Email sent: ${result.messageId}`)
    }
}
